import express from 'express';
import path from 'path';
import { getColor, setColor, isValidColor } from './colorStore';

export const app = express();

// Resolve public directory from project root so it works in dev, tests, and production
const publicDir = path.resolve(process.cwd(), 'public');

// Parse JSON bodies
app.use(express.json());

// Serve static assets from the public directory
app.use(express.static(publicDir));

// Root route should serve the index.html in /public
app.get('/', (_req, res) => {
  res.sendFile(path.join(publicDir, 'index.html'));
});

// API: get current color
app.get('/api/color', (_req, res) => {
  res.json({ color: getColor() });
});

// API: update color
app.post('/api/color', (req, res) => {
  const { color } = req.body ?? {};
  if (typeof color !== 'string') {
    return res.status(400).json({ error: 'Missing required field: color' });
  }
  const candidate = color.trim();
  if (!isValidColor(candidate)) {
    return res.status(400).json({ error: 'Invalid color format. Use hex (#RRGGBB or #RGB) or rgb(r,g,b).' });
  }
  setColor(candidate);
  return res.status(200).json({ color: getColor() });
});

export default app;

import { app } from './app';

const PORT = Number(process.env.PORT) || 3000;

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

let currentColor = '#000000';

function isValidHex(color: string): boolean {
  return /^#(?:[0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(color.trim());
}

function isByte(n: number): boolean {
  return Number.isInteger(n) && n >= 0 && n <= 255;
}

function parseRgb(color: string): { r: number; g: number; b: number } | null {
  const m = color.match(/^rgb\(\s*([0-9]{1,3})\s*,\s*([0-9]{1,3})\s*,\s*([0-9]{1,3})\s*\)$/i);
  if (!m) return null;
  const r = Number(m[1]);
  const g = Number(m[2]);
  const b = Number(m[3]);
  if (isByte(r) && isByte(g) && isByte(b)) {
    return { r, g, b };
  }
  return null;
}

function isValidRgb(color: string): boolean {
  return parseRgb(color.trim()) !== null;
}

export function isValidColor(color: string): boolean {
  const c = color.trim();
  return isValidHex(c) || isValidRgb(c);
}

function normalizeRgb(color: string): string {
  const parsed = parseRgb(color);
  if (!parsed) return color.trim().replace(/\s+/g, ' ');
  const { r, g, b } = parsed;
  return `rgb(${r}, ${g}, ${b})`;
}

export function getColor(): string {
  return currentColor;
}

export function setColor(color: string): void {
  const c = color.trim();
  if (!isValidColor(c)) {
    throw new Error('Invalid color');
  }
  currentColor = isValidHex(c) ? c.toLowerCase() : normalizeRgb(c);
}

import { describe, it, expect, beforeEach } from 'vitest';
import request from 'supertest';
import { app } from '../src/app';

async function getColor() {
  return request(app).get('/api/color');
}

async function postColor(color: unknown) {
  return request(app).post('/api/color').send({ color });
}

describe('Color API', () => {
  beforeEach(async () => {
    // Reset to default before each test
    await postColor('#000000');
  });

  it('GET /api/color returns current color', async () => {
    const res = await getColor();
    expect(res.status).toBe(200);
    expect(res.body).toHaveProperty('color');
    expect(typeof res.body.color).toBe('string');
  });

  it('defaults to #000000 after reset', async () => {
    const res = await getColor();
    expect(res.body.color).toBe('#000000');
  });

  it('POST /api/color accepts valid hex and persists', async () => {
    const set = await postColor('#ff00aa');
    expect(set.status).toBe(200);
    expect(set.body).toEqual({ color: '#ff00aa' });

    const res2 = await getColor();
    expect(res2.body.color).toBe('#ff00aa');
  });

  it('POST /api/color accepts valid rgb and persists', async () => {
    const set = await postColor('rgb(12, 34, 56)');
    expect(set.status).toBe(200);
    expect(set.body).toEqual({ color: 'rgb(12, 34, 56)' });

    const res2 = await getColor();
    expect(res2.body.color).toBe('rgb(12, 34, 56)');
  });

  it('rejects invalid inputs', async () => {
    const bad1 = await postColor('blue');
    expect(bad1.status).toBe(400);

    const bad2 = await postColor('#12345');
    expect(bad2.status).toBe(400);

    const bad3 = await postColor('rgb(300,0,0)');
    expect(bad3.status).toBe(400);

    const bad4 = await request(app).post('/api/color').send({});
    expect(bad4.status).toBe(400);
  });
});
